  target_type TEXT NOT NULL,
  target_id UUID NOT NULL,
  action TEXT NOT NULL,
  reason TEXT,
  created_at TIMESTAMP DEFAULT NOW()
);

-- 用户等级经验日志表
CREATE TABLE IF NOT EXISTS public.exp_logs (
